import React from "react";
import { Form } from "react-bootstrap";
import DatePicker from "react-datepicker";
import "react-datepicker/dist/react-datepicker.css";

function EmployeeForm({
  employee,
  setEmployee,
  errors,

  titles,
  religions,
  states,
  district,
  officelevels,
  offices,
  designations,

  selectedValues,
  setSelectedValues,

  loadDistrict,
  loadOffice,

  handleSaveConfirmation,
  handleReset,
}) {
  const updateSelected = (field, value) => {
    setSelectedValues((prev) => ({
      ...prev,
      [field]: value,
    }));
  };

  return (
    <div className="card">
      <div className="card-header d-flex justify-content-between border-0">
        <div className="header-title">
          <h5 className="card-title">
            {employee.action === "U"
              ? `Update Details of ${employee.emp_name}`
              : "Add New Employee"}
          </h5>
        </div>
      </div>

      <div className="card-body">
        <Form onSubmit={handleSaveConfirmation}>

          {/* ===================== */}
          {/* GENERAL DETAILS */}
          {/* ===================== */}

          <h6>1. General Details</h6>

          <div className="row">

            <div className="form-group col-md-4">
              <label className="form-label col-form-label-sm">
                Employee Code *
              </label>

              <input
                type="text"
                className={`form-control form-control-sm ${
                  errors.emp_code ? "is-invalid" : ""
                }`}
                value={employee.emp_code}
                disabled={employee.action === "U"}
                onChange={(e) =>
                  setEmployee({
                    ...employee,
                    emp_code: e.target.value,
                  })
                }
              />

              <div className="invalid-feedback">
                {errors.emp_code}
              </div>
            </div>

            <div className="form-group col-md-4">
              <label className="form-label col-form-label-sm">
                Title *
              </label>

              <select
                className={`form-select form-select-sm ${
                  errors.title_id ? "is-invalid" : ""
                }`}
                value={selectedValues.title}
                onChange={(e) => {
                  updateSelected("title", e.target.value);

                  setEmployee({
                    ...employee,
                    title_id: parseInt(e.target.value, 10),
                  });
                }}
              >
                <option value="">Select</option>

                {titles.map((title) => (
                  <option
                    key={title.title_id}
                    value={title.title_id}
                  >
                    {title.title_name}
                  </option>
                ))}
              </select>

              <div className="invalid-feedback">
                {errors.title_id}
              </div>
            </div>

            <div className="form-group col-md-4">
              <label className="form-label col-form-label-sm">
                Employee Name *
              </label>

              <input
                type="text"
                className={`form-control form-control-sm ${
                  errors.emp_name ? "is-invalid" : ""
                }`}
                value={employee.emp_name}
                onChange={(e) =>
                  setEmployee({
                    ...employee,
                    emp_name: e.target.value,
                  })
                }
              />

              <div className="invalid-feedback">
                {errors.emp_name}
              </div>
            </div>

          </div>

          {/* ===================== */}
          {/* CONTACT DETAILS */}
          {/* ===================== */}

          <h6 className="mt-3">2. Contact Details</h6>

          <div className="row">

            <div className="form-group col-md-4">
              <label className="form-label col-form-label-sm">
                Mobile No *
              </label>

              <input
                type="text"
                className={`form-control form-control-sm ${
                  errors.mobile_no1 ? "is-invalid" : ""
                }`}
                value={employee.mobile_no1}
                maxLength={10}
                onChange={(e) =>
                  setEmployee({
                    ...employee,
                    mobile_no1: e.target.value.replace(/\D/g, ""),
                  })
                }
              />

              <div className="invalid-feedback">
                {errors.mobile_no1}
              </div>
            </div>

            <div className="form-group col-md-4">
              <label className="form-label col-form-label-sm">
                Email *
              </label>

              <input
                type="email"
                className={`form-control form-control-sm ${
                  errors.email_id ? "is-invalid" : ""
                }`}
                value={employee.email_id}
                disabled={employee.action === "U"}
                onChange={(e) =>
                  setEmployee({
                    ...employee,
                    email_id: e.target.value,
                  })
                }
              />

              <div className="invalid-feedback">
                {errors.email_id}
              </div>
            </div>

            <div className="form-group col-md-4">
              <label className="form-label col-form-label-sm">
                State
              </label>

              <select
                className="form-select form-select-sm"
                value={selectedValues.state}
                onChange={(e) => {
                  updateSelected("state", e.target.value);

                  loadDistrict(e.target.value);

                  setEmployee({
                    ...employee,
                    state_id: parseInt(e.target.value, 10),
                  });
                }}
              >
                <option value="">Select</option>

                {states.map((state) => (
                  <option
                    key={state.state_id}
                    value={state.state_id}
                  >
                    {state.state_name}
                  </option>
                ))}
              </select>
            </div>

          </div>

          {/* ===================== */}
          {/* OFFICE DETAILS */}
          {/* ===================== */}

          <h6 className="mt-3">3. Office Details</h6>

          <div className="row">

            <div className="form-group col-md-4">
              <label className="form-label col-form-label-sm">
                Office Level *
              </label>

              <select
                className={`form-select form-select-sm ${
                  errors.office_level_id ? "is-invalid" : ""
                }`}
                value={selectedValues.officeLevel}
                onChange={(e) => {
                  updateSelected("officeLevel", e.target.value);

                  loadOffice(e.target.value);

                  setEmployee({
                    ...employee,
                    office_level_id: parseInt(
                      e.target.value,
                      10
                    ),
                  });
                }}
              >
                <option value="">Select</option>

                {officelevels.map((level) => (
                  <option
                    key={level.office_level_id}
                    value={level.office_level_id}
                  >
                    {level.office_level_name}
                  </option>
                ))}
              </select>
            </div>

            <div className="form-group col-md-4">
              <label className="form-label col-form-label-sm">
                Office *
              </label>

              <select
                className={`form-select form-select-sm ${
                  errors.office_id ? "is-invalid" : ""
                }`}
                value={selectedValues.office}
                onChange={(e) => {
                  updateSelected("office", e.target.value);

                  setEmployee({
                    ...employee,
                    office_id: e.target.value,
                  });
                }}
              >
                <option value="">Select</option>

                {offices.map((office) => (
                  <option
                    key={office.office_id}
                    value={office.office_id}
                  >
                    {office.office_name}
                  </option>
                ))}
              </select>
            </div>

            <div className="form-group col-md-4">
              <label className="form-label col-form-label-sm">
                Joining Date
              </label>

              <DatePicker
                selected={employee.joining_date}
                onChange={(date) =>
                  setEmployee({
                    ...employee,
                    joining_date: date,
                  })
                }
                className="form-control form-control-sm"
                dateFormat="dd/MM/yyyy"
              />
            </div>

          </div>

          <div className="mt-3 text-end">

            <button
              type="submit"
              className="btn btn-primary"
            >
              {employee.action === "U"
                ? "Update"
                : "Save"}
            </button>

            &nbsp;

            <button
              type="button"
              className="btn btn-danger"
              onClick={handleReset}
            >
              Cancel
            </button>

          </div>

        </Form>
      </div>
    </div>
  );
}

export default EmployeeForm;
